import type { Question } from '@/types/game';

function mk(
  id: string,
  difficulty: Question['difficulty'],
  question: string,
  optionA: string,
  optionB: string,
  optionC: string,
  optionD: string,
  correctAnswer: 'A' | 'B' | 'C' | 'D',
  hint1: string,
  hint2: string,
  hint3: string,
  hint4: string,
  eventType?: Question['eventType'],
  eventYear?: number,
): Question {
  return {
    id,
    category: 'world-cup',
    difficulty,
    question,
    optionA,
    optionB,
    optionC,
    optionD,
    correctAnswer,
    hint1,
    hint2,
    hint3,
    hint4,
    ...(eventType != null ? { eventType } : {}),
    ...(eventYear != null ? { eventYear } : {}),
  };
}

